import React, { useState } from 'react'
import cn from 'classnames'
import { ChevronDown, Box, Circle, Layers, PenTool, Square, Type } from 'react-feather'

const IconIndicator = function ({ type }) {
  switch (type) {
    case 'TEXT':
      return <Type size={13}/>
    case 'FRAME':
      return <Box size={13}/>
    case 'COMPONENT':
    case 'COMPONENT_SET':
    case 'INSTANCE':
      return <Layers size={13}/>
    case 'ELLIPSE':
      return <Circle size={13}/>
    case 'VECTOR':
    case 'LINE':
    case 'BOOLEAN_OPERATION':
      return <PenTool size={13}/>
    case 'RECTANGLE':
      return <Square size={13}/>
    default:
      return <Layers size={13}/>
  }
}

const TreeItem = function ({ node, level, selectedLayerId, collapsedIds, onToggle, onSelect }) {
  const hasChildren = node.children && node.children.length
  const collapsed = collapsedIds[node.id]
  return (
    <li className="layer-tree-item">
      <div
        className={cn('layer-tree-row', { selected: selectedLayerId===node.id })}
        style={{ paddingLeft: `${level*14 + 8}px` }}
        title={node.name}
        onClick={() => onSelect(node.id)}
      >
        <span
          className={cn('layer-tree-chevron', { hidden: !hasChildren, collapsed })}
          onClick={e => {
            e.stopPropagation()
            hasChildren && onToggle(node.id)
          }}
        >
          <ChevronDown size={14}/>
        </span>
        <span className="layer-tree-icon"><IconIndicator type={node.type}/></span>
        <span className="layer-tree-name">{node.name}</span>
      </div>
      {
        hasChildren &&
        <ul className={cn('layer-tree-children', { collapsed })}>
          {
            node.children.map(child =>
              <TreeItem
                key={child.id}
                node={child}
                level={level+1}
                selectedLayerId={selectedLayerId}
                collapsedIds={collapsedIds}
                onToggle={onToggle}
                onSelect={onSelect}
              />
            )
          }
        </ul>
      }
    </li>
  )
}

const LayerTree = function ({ canvasData, selectedLayerId, onSelect }) {
  const [collapsedIds, setCollapsedIds] = useState({})
  const toggle = id => {
    setCollapsedIds(ids => ({
      ...ids,
      [id]: !ids[id]
    }))
  }
  if (!canvasData) {
    return (
      <div className="layer-tree-empty">
        选择一个画板后查看图层
      </div>
    )
  }
  return (
    <ul className="layer-tree">
      <TreeItem
        node={canvasData}
        level={0}
        selectedLayerId={selectedLayerId}
        collapsedIds={collapsedIds}
        onToggle={toggle}
        onSelect={onSelect}
      />
    </ul>
  )
}

export default LayerTree
