import React, { Fragment } from 'react'
import cn from 'classnames'
import { withTranslation } from 'react-i18next'
import { Droplet, Image, DownloadCloud, Clock, Loader, PlayCircle } from 'react-feather'
import JSZip from 'jszip'
import { saveAs } from 'file-saver'
import Versions from './Versions'
import LottiePlayer from './LottiePlayer'
import { StyleItem } from '../items'
import { asyncForEach, isAllImageFill, getImageUrl } from 'utils/helper'
import { STYLE_TYPES } from 'utils/const'
import {
  SLICE_PLATFORMS,
  OUTPUT_FORMATS,
  groupExportSettings,
  getBaseSize,
  getOutputName,
  loadImage,
  canvasToBlob,
  addUniqueZipFile
} from 'utils/sliceExport'
import './style.scss'

class RightPanel extends React.Component {
  state = {
    tabIndex: 0,
    percentage: 0,
    progressText: '',
    selectedExportKeys: [],
    sliceSizes: {},
    format: 'PNG',
    platform: 'ios',
    selectedDensityKeys: ['1x', '2x', '3x']
  }
  changeTab = index => {
    const { tabIndex } = this.state
    const { onSlicePanelVisibleChange } = this.props
    if (tabIndex!==index) {
      this.setState({tabIndex: index})
    }
    onSlicePanelVisibleChange && onSlicePanelVisibleChange(index===1)
  }
  getSliceGroups = () => {
    const { exportSettings, currentExportIds = [], currentExportNames = [] } = this.props
    const sliceGroups = groupExportSettings(exportSettings)
    if (!currentExportIds.length && !currentExportNames.length) {
      return sliceGroups
    }
    return sliceGroups.filter(({ id, sourceSetting }) =>
      currentExportIds.indexOf(id) > -1 ||
      currentExportNames.indexOf(sourceSetting.name) > -1
    )
  }
  syncSliceGroups = () => {
    const sliceGroups = this.getSliceGroups()
    const selectedExportKeys = sliceGroups.map(({ key }) => key)
    this.setState({ selectedExportKeys })
    this.loadSliceSizes(sliceGroups)
  }
  loadSliceSizes = sliceGroups => {
    const { mode, isMock } = this.props
    sliceGroups.forEach(group => {
      const { key, sourceSetting, sourceScale } = group
      if (this.state.sliceSizes[key]) return
      loadImage(sourceSetting.offlineDataUrl || getImageUrl(sourceSetting, mode, isMock))
        .then(image => {
          this.setState(({ sliceSizes }) => ({
            sliceSizes: {
              ...sliceSizes,
              [key]: getBaseSize(image, sourceScale)
            }
          }))
        })
        .catch(() => {})
    })
  }
  setProgress = (percentage, progressText) => {
    this.setState({
      percentage,
      progressText
    })
  }
  toggleExport = key => {
    this.setState(({ selectedExportKeys }) => ({
      selectedExportKeys:
        selectedExportKeys.indexOf(key) > -1 ?
        selectedExportKeys.filter(item => item !== key) :
        [...selectedExportKeys, key]
    }))
  }
  toggleAllExports = () => {
    const sliceGroups = this.getSliceGroups()
    const { selectedExportKeys } = this.state
    const selectedVisibleKeys = sliceGroups.map(({ key }) => key).filter(key => selectedExportKeys.indexOf(key) > -1)
    const allSelected = selectedVisibleKeys.length === sliceGroups.length
    this.setState({
      selectedExportKeys: allSelected ? [] : sliceGroups.map(({ key }) => key)
    })
  }
  handlePlatformChange = e => {
    const platform = e.target.value
    this.setState({
      platform,
      selectedDensityKeys: SLICE_PLATFORMS[platform].map(({ key }) => key)
    })
  }
  toggleDensity = key => {
    this.setState(({ selectedDensityKeys }) => ({
      selectedDensityKeys:
        selectedDensityKeys.indexOf(key) > -1 ?
        selectedDensityKeys.filter(item => item !== key) :
        [...selectedDensityKeys, key]
    }))
  }
  handleDownloadSelected = async () => {
    const { percentage, selectedExportKeys, selectedDensityKeys, format, platform } = this.state
    if (percentage!==0 || !selectedExportKeys.length || !selectedDensityKeys.length) return

    const { mode, isMock, documentName } = this.props
    const selectedGroups = this.getSliceGroups().filter(({ key }) => selectedExportKeys.indexOf(key) > -1)
    const selectedDensities = SLICE_PLATFORMS[platform].filter(({ key }) => selectedDensityKeys.indexOf(key) > -1)
    const zip = new JSZip()
    const usedNames = {}
    const total = selectedGroups.length * selectedDensities.length
    let done = 0

    try {
      this.setProgress(1, '正在生成切图...')
      await asyncForEach(selectedGroups, async group => {
        const image = await loadImage(group.sourceSetting.offlineDataUrl || getImageUrl(group.sourceSetting, mode, isMock))
        const baseSize = getBaseSize(image, group.sourceScale)
        await asyncForEach(selectedDensities, async density => {
          const width = Math.max(1, Math.round(baseSize.width * density.scale))
          const height = Math.max(1, Math.round(baseSize.height * density.scale))
          const blob = await canvasToBlob(image, width, height, format)
          addUniqueZipFile(zip, getOutputName(group.name, density, format, platform), blob, usedNames)
          done += 1
          this.setProgress(Math.max(1, Math.floor((done / total) * 94)), `正在处理 ${group.name}`)
        })
      })

      this.setProgress(96, '正在压缩文件...')
      const content = await zip.generateAsync({ type: 'blob' })
      saveAs(content, `${documentName.replace(/\//g, '-')}-selected-exports.zip`)
      this.setProgress(100, '完成下载！')
      const timer = setTimeout(() => {
        this.setProgress(0, '')
        clearTimeout(timer)
      }, 800)
    } catch (error) {
      console.error(error)
      this.setProgress(0, error && error.message ? error.message : '切图生成失败')
    }
  }
  componentDidMount() {
    this.syncSliceGroups()
  }
  componentDidUpdate(prevProps) {
    if (
      prevProps.exportSettings !== this.props.exportSettings ||
      prevProps.mode !== this.props.mode ||
      prevProps.isMock !== this.props.isMock ||
      prevProps.currentExportIds !== this.props.currentExportIds ||
      prevProps.currentExportNames !== this.props.currentExportNames
    ) {
      this.syncSliceGroups()
    }
  }
  componentWillUnmount() {
    const { onSlicePanelVisibleChange } = this.props
    onSlicePanelVisibleChange && onSlicePanelVisibleChange(false)
  }
  render () {
    const { mode, isMock, styles, propsPanelState, onShowDetail, versionData, t } = this.props
    const {
      tabIndex,
      percentage,
      progressText,
      selectedExportKeys,
      sliceSizes,
      format,
      platform,
      selectedDensityKeys
    } = this.state
    const sliceGroups = this.getSliceGroups()
    const selectedVisibleKeys = sliceGroups.map(({ key }) => key).filter(key => selectedExportKeys.indexOf(key) > -1)
    const allSelected = !!sliceGroups.length && selectedVisibleKeys.length === sliceGroups.length
    const selectedDensities = SLICE_PLATFORMS[platform].filter(({ key }) => selectedDensityKeys.indexOf(key) > -1)
    const selectedOutputCount = selectedVisibleKeys.length * selectedDensities.length
    return (
      <div className="right-panel">
        <div
          className={cn('panel-mask', `mask-${propsPanelState}`)}
        />
        <ul className="panel-tabs">
          <li className={cn({'selected': tabIndex===0})} onClick={() => this.changeTab(0)}><Droplet size={14}/>{t('tab style')}</li>
          <li className={cn({'selected': tabIndex===1})} onClick={() => this.changeTab(1)}><Image size={14}/>{t('tab slice')}</li>
          <li className={cn({'selected': tabIndex===2})} onClick={() => this.changeTab(2)}><PlayCircle size={14}/>动画</li>
          {
            versionData &&
            <li className={cn({'selected': tabIndex===3})} onClick={() => this.changeTab(3)}><Clock size={14}/>{t('tab version')}</li>
          }
        </ul>
        <ul className={cn('panel-list', {'hide': tabIndex!==0})}>
          {
            Object.keys(styles).map(key =>
              key!=='GRID' && styles[key] &&
              <Fragment key={key}>
                <li className="list-title">{ t(STYLE_TYPES[key]) }</li>
                {
                  styles[key] &&
                  styles[key]
                    .filter(style => key==='FILL' ? !isAllImageFill(style.items) : true)
                    .map((style, index) =>
                      <li key={index}>
                        <StyleItem
                          styles={style.items}
                          styleName={style.name}
                          styleType={style.styleType}
                          isSelectable
                          onClick={() => onShowDetail(style)}
                        />
                      </li>
                    )
                }
              </Fragment>
            )
          }
        </ul>
        <ul className={cn('panel-exports', {'hide': tabIndex!==1})}>
            {
              !!sliceGroups.length ?
              <>
                <li className="exports-select-all">
                  <label>
                    <input type="checkbox" checked={allSelected} onChange={this.toggleAllExports}/>
                    <span>全选</span>
                  </label>
                  <em>已选 {selectedVisibleKeys.length} 个切图</em>
                </li>
                <li className="exports-list-wrap">
                  <ul
                    className="exports-select-list"
                  >
                    {
                      sliceGroups.map(group => {
                        const checked = selectedExportKeys.indexOf(group.key) > -1
                        const size = sliceSizes[group.key]
                        return (
                          <li key={group.key} className={cn({ selected: checked })}>
                            <label>
                              <input type="checkbox" checked={checked} onChange={() => this.toggleExport(group.key)}/>
                              <span className="export-thumb" style={{backgroundImage: `url(${group.sourceSetting.offlineDataUrl || getImageUrl(group.sourceSetting, mode, isMock)})`}}/>
                              <span className="export-meta">
                                <strong>{group.name}</strong>
                                <em>{size ? `${size.width}px x ${size.height}px` : ''}</em>
                              </span>
                            </label>
                          </li>
                        )
                      })
                    }
                  </ul>
                </li>
                <li className="exports-config">
                  <h5>下载配置</h5>
                  <div className="exports-config-grid">
                    <label>
                      <span>下载切图样式</span>
                      <select value={format} onChange={e => this.setState({ format: e.target.value })}>
                        {OUTPUT_FORMATS.map(item => <option key={item} value={item}>{item}</option>)}
                      </select>
                    </label>
                    <label>
                      <span>切图使用平台</span>
                      <select value={platform} onChange={this.handlePlatformChange}>
                        <option value="ios">iOS</option>
                        <option value="android">Android</option>
                      </select>
                    </label>
                  </div>
                  <ul className="exports-density-list">
                    {SLICE_PLATFORMS[platform].map(density => (
                      <li key={density.key}>
                        <label>
                          <input
                            type="checkbox"
                            checked={selectedDensityKeys.indexOf(density.key) > -1}
                            onChange={() => this.toggleDensity(density.key)}
                          />
                          <span>{density.label}</span>
                        </label>
                      </li>
                    ))}
                  </ul>
                  <div className="exports-config-grid">
                    <label>
                      <span>PNG 图片压缩</span>
                      <select value="none" disabled>
                        <option value="none">不压缩</option>
                      </select>
                    </label>
                  </div>
                  <button
                    className={cn('exports-download-selected', {'is-downloading': percentage})}
                    disabled={!selectedOutputCount || percentage}
                    onClick={this.handleDownloadSelected}
                  >
                    <span>{ progressText || `下载 ${selectedOutputCount} 个切图` }</span>
                    { percentage ? <Loader size={14} className="motion-loading"/> : <DownloadCloud size={14}/> }
                    <div className="download-all-progress" style={{width: `${percentage}%`}}/>
                  </button>
                </li>
              </> :
              <li className="exports-empty">{t('no exports')}</li>
            }
          </ul>
        <LottiePlayer visible={tabIndex===2}/>
        {
          versionData &&
          <Versions visible={tabIndex===3} versionData={versionData}/>
        }
      </div>
    )
  }
}

export default withTranslation('right')(RightPanel)
